import{_ as o,o as t,c as r,ak as a}from"./chunks/framework.B0XXUb7R.js";const m=JSON.parse('{"title":"Monorepo architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),n={name:"architecture.md"};function s(d,e,c,i,p,l){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="monorepo-architecture" tabindex="-1">Monorepo architecture <a class="header-anchor" href="#monorepo-architecture" aria-label="Permalink to “Monorepo architecture”">​</a></h1><h2 id="why-this-monorepo-exists" tabindex="-1">Why this monorepo exists <a class="header-anchor" href="#why-this-monorepo-exists" aria-label="Permalink to “Why this monorepo exists”">​</a></h2><p>The BC Government WordPress monorepo brings <strong>themes, plugins, and shared packages</strong> into one Git repository so teams can:</p><ul><li><strong>Share tooling</strong> — One set of lint, test, and build commands (<code>@wordpress/scripts</code>, PHPCS, Playwright, PHPUnit) instead of per-repo copies that drift apart.</li><li><strong>Enforce consistency</strong> — Root-level configuration and Nx task defaults keep project structure and scripts aligned.</li><li><strong>Preserve history</strong> — Existing repositories can be imported with Git history intact (<code>nx import</code>), so audits and blame remain meaningful after consolidation.</li><li><strong>Coordinate releases</strong> — Version tags are namespaced per Nx project (<code>&lt;project-name&gt;/v&lt;semver&gt;</code>), matching Composer consumption patterns documented in <a href="./release-and-deployment">Release and deployment</a>.</li></ul><h2 id="repository-layout" tabindex="-1">Repository layout <a class="header-anchor" href="#repository-layout" aria-label="Permalink to “Repository layout”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>plugins/</code></td><td>WordPress plugins; each shipping plugin is typically one folder with <code>package.json</code>, <code>composer.json</code>, and <code>project.json</code>.</td></tr><tr><td><code>themes/</code></td><td>WordPress themes; same expectations as plugins for Nx and package metadata.</td></tr><tr><td><code>packages/</code></td><td>Shared libraries (for example PHPUnit config consumed via Composer path repositories).</td></tr><tr><td><code>tools/</code></td><td>Internal tooling (for example the <code>monorepo</code> Nx plugin and doc sync script).</td></tr><tr><td><code>docs/</code></td><td>VitePress site source and generated <code>docs/content/</code> from package-local docs.</td></tr><tr><td><code>.github/workflows/</code></td><td>CI/CD workflows (PR checks, tagged releases, docs deploy).</td></tr></tbody></table><h2 id="discovering-projects-nx" tabindex="-1">Discovering projects (Nx) <a class="header-anchor" href="#discovering-projects-nx" aria-label="Permalink to “Discovering projects (Nx)”">​</a></h2><p><strong>Nx</strong> is the task runner and project graph engine:</p><ul><li>Each <strong>application</strong> (theme or plugin) has a <code>project.json</code> at its root declaring the project <code>name</code>, <code>root</code>, and which <strong>targets</strong> it implements (<code>build</code>, <code>composer-install</code>, <code>wp-env-start</code>, and so on).</li><li>Default target behavior (commands, caching, <code>dependsOn</code>) lives in <a href="https://github.com/bcgov/wordpress-monorepo/blob/main/nx.json" target="_blank" rel="noreferrer"><code>nx.json</code></a> under <code>targetDefaults</code>.</li><li><strong>Discover projects:</strong> <code>npx nx show projects</code></li><li><strong>Graph (local):</strong> <code>npx nx graph</code></li><li><strong>Affected projects (for a branch):</strong> <code>npx nx show projects --affected</code> (compare with <code>defaultBase</code>, usually <code>origin/main</code>)</li></ul><p>Pull request CI uses <strong><code>nx affected</code></strong> so only changed projects and their graph dependencies run expensive build and test targets.</p><h2 id="dependency-relationships" tabindex="-1">Dependency relationships <a class="header-anchor" href="#dependency-relationships" aria-label="Permalink to “Dependency relationships”">​</a></h2><h3 id="build-order-dependson" tabindex="-1">Build order (<code>dependsOn</code>) <a class="header-anchor" href="#build-order-dependson" aria-label="Permalink to “Build order (dependsOn)”">​</a></h3><p>In <code>nx.json</code>, the <code>build</code> and <code>start</code> targets use <code>&quot;dependsOn&quot;: [&quot;^build&quot;]</code>. That means Nx builds <strong>upstream</strong> projects in the graph first. Any project that should trigger downstream builds must be linked in the graph (for example via <code>implicitDependencies</code> or package relationships Nx understands).</p><h3 id="implicitdependencies" tabindex="-1"><code>implicitDependencies</code> <a class="header-anchor" href="#implicitdependencies" aria-label="Permalink to “implicitDependencies”">​</a></h3><p>Projects may list other projects or paths in <code>implicitDependencies</code> so changes there mark dependents as affected. Today, generated plugins and themes often include <code>packages/phpunit-config/</code> so PHPUnit-related changes surface in CI for those apps.</p><h3 id="wordpress-parent-and-child-themes" tabindex="-1">WordPress parent and child themes <a class="header-anchor" href="#wordpress-parent-and-child-themes" aria-label="Permalink to “WordPress parent and child themes”">​</a></h3><p><strong>Child themes</strong> may depend on a <strong>parent theme</strong> at runtime (WordPress <code>Template:</code> header, Composer packages, or shared design tokens). That relationship might live outside this monorepo (for example a parent theme in another repository). Document parent/child links in the child theme’s <code>readme.txt</code>, <code>composer.json</code>, and package docs. If both parent and child are ever in the same monorepo, add explicit Nx graph edges (for example <code>implicitDependencies</code>) so CI builds and tests run in the right order.</p><h2 id="pnpm-workspaces" tabindex="-1">pnpm workspaces <a class="header-anchor" href="#pnpm-workspaces" aria-label="Permalink to “pnpm workspaces”">​</a></h2><p>JavaScript dependencies are managed with <strong>pnpm</strong> and <strong><code>pnpm-workspace.yaml</code></strong>, which includes <code>themes/*</code>, <code>plugins/*</code>, <code>packages/*</code>, and <code>tools/*</code>. See <a href="./package-management">Package management</a>.</p>',19)])])}const g=o(n,[["render",s]]);export{m as __pageData,g as default};
